/**
 * MiniChart — Lightweight Chart.js-compatible Canvas Chart Engine
 * Built for air-gapped / offline environments.
 * Supports: line chart, multi-axis (y-temp, y-perf, y-pct), legend,
 *           tooltip (crosshair), fill, dashed lines, responsive sizing.
 *
 * Drop-in replacement: new Chart(canvas, config) — same API surface
 * used by DX Sandbox timeline.js.
 *
 * To replace with real Chart.js when internet is available:
 *   curl -L "https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js" -o static/js/chart.umd.min.js
 */
(function (global) {
  "use strict";

  /* ── helpers ───────────────────────────────────── */
  function hexToRgba(hex, a) {
    if (!hex) return "rgba(180,180,180," + a + ")";
    hex = hex.replace("#", "");
    if (hex.length <= 4) {
      hex = hex.split("").map(function (c) { return c + c; }).join("");
    }
    var r = parseInt(hex.substring(0, 2), 16) || 0;
    var g = parseInt(hex.substring(2, 4), 16) || 0;
    var b = parseInt(hex.substring(4, 6), 16) || 0;
    return "rgba(" + r + "," + g + "," + b + "," + a + ")";
  }

  function parseColor(c) {
    if (!c) return "rgba(180,180,180,1)";
    if (c.startsWith("rgba") || c.startsWith("rgb")) return c;
    if (c.length === 9 && c.startsWith("#")) {
      var alpha = parseInt(c.substring(7, 9), 16) / 255;
      return hexToRgba(c.substring(0, 7), alpha.toFixed(2));
    }
    return c;
  }

  function niceNum(range, round) {
    if (range <= 0) range = 1;
    var exp = Math.floor(Math.log10(range));
    var frac = range / Math.pow(10, exp);
    var nice;
    if (round) {
      if (frac < 1.5) nice = 1;
      else if (frac < 3) nice = 2;
      else if (frac < 7) nice = 5;
      else nice = 10;
    } else {
      if (frac <= 1) nice = 1;
      else if (frac <= 2) nice = 2;
      else if (frac <= 5) nice = 5;
      else nice = 10;
    }
    return nice * Math.pow(10, exp);
  }

  function calcTicks(minVal, maxVal, maxTicks) {
    if (maxVal === minVal) maxVal = minVal + 1;
    maxTicks = maxTicks || 8;
    var range = niceNum(maxVal - minVal, false);
    var spacing = niceNum(range / (maxTicks - 1), true);
    var lo = Math.floor(minVal / spacing) * spacing;
    var hi = Math.ceil(maxVal / spacing) * spacing;
    var ticks = [];
    for (var v = lo; v <= hi + spacing * 0.5; v += spacing) {
      ticks.push(parseFloat(v.toFixed(10)));
    }
    return ticks;
  }

  /* ── MiniChart constructor ─────────────────────── */
  function Chart(canvasEl, config) {
    if (typeof canvasEl === "string") canvasEl = document.getElementById(canvasEl);
    if (!canvasEl) { console.warn("[MiniChart] Canvas element not found."); return; }
    this.canvas = canvasEl instanceof HTMLCanvasElement ? canvasEl : canvasEl.getContext ? canvasEl : null;
    if (!this.canvas) { console.warn("[MiniChart] Canvas not resolved."); return; }

    this.ctx = this.canvas.getContext("2d");
    this.config = config || {};
    this.data = config.data || {};
    this.options = config.options || {};
    this._hoverIndex = -1;
    this._destroyed = false;

    (this.data.datasets || []).forEach(function (ds) {
      ds.borderWidth = ds.borderWidth || 2;
      ds.pointRadius = ds.pointRadius != null ? ds.pointRadius : 3;
      ds.tension = ds.tension || 0;
      ds.fill = ds.fill != null ? ds.fill : false;
      ds.borderDash = ds.borderDash || [];
      ds.hidden = false;
    });

    this._boundResize = this._onResize.bind(this);
    this._boundMouse = this._onMouse.bind(this);
    this._boundClick = this._onClick.bind(this);
    this._boundLeave = this._onLeave.bind(this);

    window.addEventListener("resize", this._boundResize);
    this.canvas.addEventListener("mousemove", this._boundMouse);
    this.canvas.addEventListener("click", this._boundClick);
    this.canvas.addEventListener("mouseleave", this._boundLeave);

    this._layout = {};
    this._legendItems = [];
    this.render();
  }

  Chart.register = function () {};
  Chart.defaults = { font: {}, plugins: { legend: {}, tooltip: {} } };

  Chart.prototype.destroy = function () {
    this._destroyed = true;
    window.removeEventListener("resize", this._boundResize);
    if (this.canvas) {
      this.canvas.removeEventListener("mousemove", this._boundMouse);
      this.canvas.removeEventListener("click", this._boundClick);
      this.canvas.removeEventListener("mouseleave", this._boundLeave);
    }
  };

  Chart.prototype.update = function () { this.render(); };
  Chart.prototype.resize = function () { this.render(); };

  Chart.prototype._onResize = function () {
    if (this._destroyed) return;
    if (this._resizeTimer) clearTimeout(this._resizeTimer);
    this._resizeTimer = setTimeout(this.render.bind(this), 100);
  };

  Chart.prototype._onMouse = function (e) {
    if (this._destroyed) return;
    var rect = this.canvas.getBoundingClientRect();
    var x = (e.clientX - rect.left) * (this.canvas.width / rect.width);
    var y = (e.clientY - rect.top) * (this.canvas.height / rect.height);
    var L = this._layout;
    if (!L || !L.plotW) return;
    this._mouseX = x; this._mouseY = y;

    var labels = this.data.labels || [];
    if (!labels.length) return;
    var dpr = window.devicePixelRatio || 1;
    var relX = (x / dpr) - L.plotX;
    var idx = Math.round(relX / (L.plotW / Math.max(labels.length - 1, 1)));
    idx = Math.max(0, Math.min(labels.length - 1, idx));
    if (idx !== this._hoverIndex) {
      this._hoverIndex = idx;
      this.render();
    }
  };

  Chart.prototype._onLeave = function () {
    if (this._destroyed) return;
    this._hoverIndex = -1;
    this.render();
  };

  Chart.prototype._onClick = function (e) {
    if (this._destroyed) return;
    var rect = this.canvas.getBoundingClientRect();
    var dpr = window.devicePixelRatio || 1;
    var x = (e.clientX - rect.left) * dpr;
    var y = (e.clientY - rect.top) * dpr;
    var items = this._legendItems || [];
    for (var i = 0; i < items.length; i++) {
      var it = items[i];
      if (x / dpr >= it.x && x / dpr <= it.x + it.w && y / dpr >= it.y && y / dpr <= it.y + it.h) {
        this.data.datasets[it.dsIdx].hidden = !this.data.datasets[it.dsIdx].hidden;
        this.render();
        return;
      }
    }
  };

  /* ── Main render ───────────────────────────────── */
  Chart.prototype.render = function () {
    if (this._destroyed) return;
    var canvas = this.canvas, ctx = this.ctx;
    var data = this.data, opts = this.options;
    var dpr = window.devicePixelRatio || 1;

    var parent = canvas.parentElement;
    var dispW = parent ? parent.clientWidth : canvas.clientWidth || 600;
    var dispH = parent ? Math.max(parent.clientHeight, 280) : 400;
    canvas.style.width = dispW + "px";
    canvas.style.height = dispH + "px";
    canvas.width = dispW * dpr;
    canvas.height = dispH * dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    var W = dispW, H = dispH;
    ctx.clearRect(0, 0, W, H);

    var labels = data.labels || [];
    var datasets = data.datasets || [];
    if (!labels.length) return;

    var marginTop = 48, marginBottom = 46, marginLeft = 68, marginRight = 68;
    var scales = opts.scales || {};
    var axisKeys = Object.keys(scales);
    var rightAxes = axisKeys.filter(function (k) { return k !== "x" && scales[k].position === "right"; });
    if (rightAxes.length > 1) marginRight = 80;

    var plotX = marginLeft, plotY = marginTop;
    var plotW = W - marginLeft - marginRight;
    var plotH = H - marginTop - marginBottom;
    if (plotW < 40) plotW = 40;
    if (plotH < 40) plotH = 40;
    this._layout = { plotX: plotX, plotY: plotY, plotW: plotW, plotH: plotH };

    var gridColor = "rgba(255,255,255,0.08)";
    var textColor = "#b0b0b0";

    // ── Axis ranges ──
    var axisRanges = {};
    var primaryYAxis = null;
    axisKeys.forEach(function (k) {
      if (k === "x") return;
      if (!primaryYAxis && scales[k].position !== "right") primaryYAxis = k;
      var sc = scales[k];
      var min = sc.min != null ? sc.min : Infinity;
      var max = sc.max != null ? sc.max : -Infinity;
      datasets.forEach(function (ds) {
        if (ds.hidden) return;
        if ((ds.yAxisID || axisKeys.find(function(a){return a !== "x";}) || "y") !== k) return;
        (ds.data || []).forEach(function (v) {
          if (v < min) min = v;
          if (v > max) max = v;
        });
      });
      if (min === Infinity) { min = 0; max = 100; }
      if (min === max) max = min + 1;
      var pad = (max - min) * 0.1;
      if (sc.min != null) min = sc.min; else min = Math.max(0, min - pad);
      if (sc.max != null) max = sc.max; else max = max + pad;
      var ticks = calcTicks(min, max, 8);
      axisRanges[k] = { min: ticks[0], max: ticks[ticks.length - 1], ticks: ticks };
    });
    if (!primaryYAxis) primaryYAxis = axisKeys.find(function(k){return k!=="x";}) || "y";

    // ── Grid lines ──
    ctx.strokeStyle = gridColor; ctx.lineWidth = 1;
    if (axisRanges[primaryYAxis]) {
      axisRanges[primaryYAxis].ticks.forEach(function (val) {
        var ar = axisRanges[primaryYAxis];
        var py = plotY + plotH - ((val - ar.min) / (ar.max - ar.min)) * plotH;
        ctx.beginPath(); ctx.moveTo(plotX, py); ctx.lineTo(plotX + plotW, py); ctx.stroke();
      });
    }

    // ── Axis labels ──
    ctx.font = "11px -apple-system, BlinkMacSystemFont, sans-serif";
    ctx.textBaseline = "middle";
    axisKeys.forEach(function (k) {
      if (k === "x") return;
      var sc = scales[k], ar = axisRanges[k];
      if (!ar) return;
      var showTicks = !(sc.ticks && sc.ticks.display === false);
      if (!showTicks) return;
      var isRight = sc.position === "right";
      var color = (sc.ticks && sc.ticks.color) || textColor;
      ctx.fillStyle = color;
      ctx.textAlign = isRight ? "left" : "right";
      ar.ticks.forEach(function (val) {
        var py = plotY + plotH - ((val - ar.min) / (ar.max - ar.min)) * plotH;
        ctx.fillText(val >= 100 ? val.toFixed(0) : val.toFixed(1), isRight ? plotX + plotW + 8 : plotX - 8, py);
      });
      if (sc.title && sc.title.display) {
        ctx.save();
        ctx.fillStyle = sc.title.color || color;
        ctx.font = (sc.title.font && sc.title.font.size || 11) + "px sans-serif";
        var cx = isRight ? plotX + plotW + 50 : plotX - 52;
        ctx.translate(cx, plotY + plotH / 2);
        ctx.rotate(isRight ? Math.PI / 2 : -Math.PI / 2);
        ctx.textAlign = "center";
        ctx.fillText(sc.title.text || "", 0, 0);
        ctx.restore();
      }
    });

    // X axis
    var xScale = scales.x || {};
    ctx.fillStyle = (xScale.ticks && xScale.ticks.color) || textColor;
    ctx.textAlign = "center"; ctx.textBaseline = "top";
    var maxXTicks = (xScale.ticks && xScale.ticks.maxTicksLimit) || 13;
    var xStep = Math.max(1, Math.ceil(labels.length / maxXTicks));
    labels.forEach(function (lab, i) {
      if (i % xStep !== 0 && i !== labels.length - 1) return;
      var px = plotX + (i / Math.max(labels.length - 1, 1)) * plotW;
      ctx.fillText(typeof lab === "number" ? lab.toFixed(1) : lab, px, plotY + plotH + 6);
    });
    if (xScale.title && xScale.title.display) {
      ctx.fillStyle = xScale.title.color || textColor;
      ctx.font = (xScale.title.font && xScale.title.font.size || 12) + "px sans-serif";
      ctx.fillText(xScale.title.text || "", plotX + plotW / 2, plotY + plotH + 28);
    }

    // ── Plot border ──
    ctx.strokeStyle = "rgba(255,255,255,0.12)"; ctx.lineWidth = 1;
    ctx.strokeRect(plotX, plotY, plotW, plotH);

    // ── Draw datasets (back to front) ──
    var self = this;
    var sortedDs = datasets.map(function (ds, i) { return { ds: ds, idx: i }; });
    sortedDs.sort(function (a, b) { return (b.ds.order || 0) - (a.ds.order || 0); });

    sortedDs.forEach(function (item) {
      var ds = item.ds;
      if (ds.hidden) return;
      var yKey = ds.yAxisID || primaryYAxis;
      var ar = axisRanges[yKey];
      if (!ar) return;

      var points = [];
      (ds.data || []).forEach(function (val, i) {
        var px = plotX + (i / Math.max(labels.length - 1, 1)) * plotW;
        var py = plotY + plotH - ((val - ar.min) / (ar.max - ar.min)) * plotH;
        points.push({ x: px, y: py, val: val });
      });
      if (!points.length) return;

      // fill
      if (ds.fill) {
        ctx.beginPath();
        self._tracePath(ctx, points, ds.tension);
        ctx.lineTo(points[points.length - 1].x, plotY + plotH);
        ctx.lineTo(points[0].x, plotY + plotH);
        ctx.closePath();
        ctx.fillStyle = parseColor(ds.backgroundColor || hexToRgba(ds.borderColor, 0.12));
        ctx.fill();
      }

      // line
      ctx.beginPath();
      ctx.strokeStyle = parseColor(ds.borderColor || "#888");
      ctx.lineWidth = ds.borderWidth || 2;
      if (ds.borderDash && ds.borderDash.length) ctx.setLineDash(ds.borderDash);
      else ctx.setLineDash([]);
      self._tracePath(ctx, points, ds.tension);
      ctx.stroke();
      ctx.setLineDash([]);
    });

    // ── Crosshair + tooltip ──
    if (this._hoverIndex >= 0 && this._hoverIndex < labels.length) {
      var hi = this._hoverIndex;
      var cx = plotX + (hi / Math.max(labels.length - 1, 1)) * plotW;

      ctx.strokeStyle = "rgba(255,255,255,0.25)"; ctx.lineWidth = 1;
      ctx.setLineDash([4, 4]);
      ctx.beginPath(); ctx.moveTo(cx, plotY); ctx.lineTo(cx, plotY + plotH); ctx.stroke();
      ctx.setLineDash([]);

      datasets.forEach(function (ds) {
        if (ds.hidden) return;
        var yKey = ds.yAxisID || primaryYAxis;
        var ar = axisRanges[yKey];
        if (!ar || ds.data[hi] == null) return;
        var val = ds.data[hi];
        var py = plotY + plotH - ((val - ar.min) / (ar.max - ar.min)) * plotH;
        ctx.beginPath(); ctx.arc(cx, py, 4.5, 0, Math.PI * 2);
        ctx.fillStyle = parseColor(ds.borderColor);
        ctx.fill();
        ctx.strokeStyle = "#fff"; ctx.lineWidth = 1.5; ctx.stroke();
      });

      // tooltip
      var tooltipLines = [];
      var timeLabel = labels[hi];
      tooltipLines.push({ text: "Time: " + (typeof timeLabel === "number" ? timeLabel.toFixed(1) : timeLabel) + " min", head: true });
      datasets.forEach(function (ds) {
        if (ds.hidden) return;
        var val = ds.data[hi]; if (val == null) return;
        var lbl = ds.label || "";
        var icon = "";
        if (lbl.includes("Temp")) icon = "🌡️ ";
        else if (lbl.includes("FPS")) icon = "📈 ";
        else if (lbl.includes("Latency")) icon = "⏱️ ";
        else if (lbl.includes("Power")) icon = "⚡ ";
        else if (lbl.includes("Throttle")) icon = "🔥 ";
        var unit = "";
        if (lbl.includes("Temp")) unit = "°C";
        else if (lbl.includes("Latency")) unit = "ms";
        else if (lbl.includes("Power")) unit = "W";
        else if (lbl.includes("Throttle")) unit = "%";
        tooltipLines.push({ text: icon + lbl + ": " + val.toFixed(1) + unit, color: ds.borderColor });
      });

      ctx.font = "11px monospace";
      var maxLW = 0;
      tooltipLines.forEach(function (l) { var w = ctx.measureText(l.text).width; if (w > maxLW) maxLW = w; });
      var ttW = maxLW + 28, ttH = tooltipLines.length * 19 + 16;
      var ttX = cx + 16, ttY = plotY + 12;
      if (ttX + ttW > plotX + plotW - 4) ttX = cx - ttW - 16;
      if (ttY + ttH > plotY + plotH) ttY = plotY + plotH - ttH;

      // shadow
      ctx.shadowColor = "rgba(0,0,0,0.4)"; ctx.shadowBlur = 12; ctx.shadowOffsetY = 4;
      self._roundRect(ctx, ttX, ttY, ttW, ttH, 8);
      ctx.fillStyle = "rgba(16,16,28,0.94)";
      ctx.fill();
      ctx.shadowColor = "transparent"; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;

      ctx.strokeStyle = "rgba(255,255,255,0.12)"; ctx.lineWidth = 1;
      self._roundRect(ctx, ttX, ttY, ttW, ttH, 8);
      ctx.stroke();

      ctx.textAlign = "left"; ctx.textBaseline = "top";
      tooltipLines.forEach(function (l, li) {
        ctx.font = l.head ? "bold 11px monospace" : "11px monospace";
        ctx.fillStyle = l.head ? "#fff" : (l.color ? parseColor(l.color) : "#ccc");
        ctx.fillText(l.text, ttX + 14, ttY + 10 + li * 19);
      });
    }

    // ── Legend ──
    this._drawLegend(ctx, W, datasets, textColor);
  };

  /* ── Trace smooth/linear path ──────────────────── */
  Chart.prototype._tracePath = function (ctx, pts, tension) {
    if (!pts.length) return;
    ctx.moveTo(pts[0].x, pts[0].y);
    if (tension <= 0 || pts.length < 3) {
      for (var i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
      return;
    }
    for (var i = 0; i < pts.length - 1; i++) {
      var p0 = pts[Math.max(0, i - 1)];
      var p1 = pts[i];
      var p2 = pts[i + 1];
      var p3 = pts[Math.min(pts.length - 1, i + 2)];
      var cp1x = p1.x + (p2.x - p0.x) * tension / 3;
      var cp1y = p1.y + (p2.y - p0.y) * tension / 3;
      var cp2x = p2.x - (p3.x - p1.x) * tension / 3;
      var cp2y = p2.y - (p3.y - p1.y) * tension / 3;
      ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, p2.x, p2.y);
    }
  };

  /* ── Round rect ────────────────────────────────── */
  Chart.prototype._roundRect = function (ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y); ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r); ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h); ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r); ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  };

  /* ── Legend ─────────────────────────────────────── */
  Chart.prototype._drawLegend = function (ctx, W, datasets, textColor) {
    this._legendItems = [];
    ctx.font = "11px -apple-system, BlinkMacSystemFont, sans-serif";
    ctx.textBaseline = "middle";

    var items = [];
    var totalW = 0;
    datasets.forEach(function (ds, i) {
      var label = ds.label || ("Dataset " + (i + 1));
      var tw = ctx.measureText(label).width;
      var itemW = 28 + tw + 18;
      items.push({ label: label, color: ds.borderColor || "#888", w: itemW, idx: i, hidden: ds.hidden, dash: ds.borderDash || [] });
      totalW += itemW;
    });

    var startX = Math.max(10, (W - totalW) / 2);
    var ly = 18, curX = startX;
    var self = this;

    items.forEach(function (item) {
      if (item.hidden) ctx.globalAlpha = 0.3;
      // color line
      ctx.strokeStyle = parseColor(item.color);
      ctx.lineWidth = 2.5;
      if (item.dash.length) ctx.setLineDash(item.dash);
      else ctx.setLineDash([]);
      ctx.beginPath(); ctx.moveTo(curX, ly); ctx.lineTo(curX + 18, ly); ctx.stroke();
      ctx.setLineDash([]);
      // label
      ctx.fillStyle = item.hidden ? "rgba(180,180,180,0.4)" : textColor;
      ctx.textAlign = "left";
      ctx.fillText(item.label, curX + 23, ly);
      ctx.globalAlpha = 1;
      // hit area
      self._legendItems.push({ dsIdx: item.idx, x: curX - 2, y: ly - 9, w: item.w, h: 18 });
      curX += item.w;
    });
  };

  global.Chart = Chart;
})(typeof window !== "undefined" ? window : this);
